export function resolveAppUrl(rawAppUrl: string): {
  appUrl: string;
  returnOrigin: string;
  returnUrl: string;
} {
  let appUrl: URL;
  try {
    appUrl = new URL(rawAppUrl);
  } catch {
    throw new Error("VANA_APP_URL must be a valid HTTP or HTTPS URL.");
  }
  if (appUrl.protocol !== "http:" && appUrl.protocol !== "https:") {
    throw new Error("VANA_APP_URL must be a valid HTTP or HTTPS URL.");
  }

  return {
    appUrl: appUrl.toString(),
    returnOrigin: appUrl.origin,
    returnUrl: new URL("/connect/return", appUrl.origin).toString(),
  };
}

import { createHash, createHmac, timingSafeEqual } from "node:crypto";
import { REQUEST_BINDING_TTL_MS, VANA_APP } from "./constants";
import type { VanaRuntime } from "./runtime";

const COOKIE_PREFIX = "vana_request_";
const BINDING_VERSION = 1;

export type RequestBinding = {
  version: typeof BINDING_VERSION;
  requestId: string;
  appId: typeof VANA_APP.id;
  source: typeof VANA_APP.source;
  scope: typeof VANA_APP.scope;
  returnOrigin: string;
  runtime: VanaRuntime;
  expiresAt: number;
};

type CookieReader = {
  get(name: string): { value: string } | undefined;
};

type CookieWriter = {
  set(
    name: string,
    value: string,
    options: {
      httpOnly: true;
      sameSite: "lax";
      secure: boolean;
      path: "/";
    },
  ): void;
};

export function requestBindingCookieName(requestId: string): string {
  const requestHash = createHash("sha256").update(requestId).digest("base64url");
  return `${COOKIE_PREFIX}${requestHash}`;
}

export function createRequestBinding(
  input: {
    requestId: string;
    runtime: VanaRuntime;
    returnOrigin: string;
    now?: number;
  },
  secret: string,
): string {
  const payload: RequestBinding = {
    version: BINDING_VERSION,
    requestId: input.requestId,
    appId: VANA_APP.id,
    source: VANA_APP.source,
    scope: VANA_APP.scope,
    returnOrigin: input.returnOrigin,
    runtime: input.runtime,
    expiresAt: (input.now ?? Date.now()) + REQUEST_BINDING_TTL_MS,
  };
  const encoded = Buffer.from(JSON.stringify(payload)).toString("base64url");
  return `${encoded}.${sign(encoded, secret)}`;
}

export function setRequestBindingCookie(
  cookies: CookieWriter,
  requestId: string,
  binding: string,
  secure: boolean,
): void {
  cookies.set(requestBindingCookieName(requestId), binding, {
    httpOnly: true,
    sameSite: "lax",
    secure,
    path: "/",
  });
}

export function readRequestBinding(
  cookies: CookieReader,
  input: {
    requestId: string;
    returnOrigin: string;
    now?: number;
  },
  secret: string,
): RequestBinding | null {
  const value = cookies.get(requestBindingCookieName(input.requestId))?.value;
  if (!value || value.length > 4096) return null;

  const separator = value.lastIndexOf(".");
  if (separator <= 0) return null;

  const encoded = value.slice(0, separator);
  const signature = value.slice(separator + 1);
  if (!safeEqual(signature, sign(encoded, secret))) return null;

  try {
    const parsed: unknown = JSON.parse(Buffer.from(encoded, "base64url").toString("utf8"));
    if (!isRequestBinding(parsed)) return null;
    if (parsed.requestId !== input.requestId) return null;
    if (parsed.returnOrigin !== input.returnOrigin) return null;
    if (parsed.expiresAt <= (input.now ?? Date.now())) return null;
    return parsed;
  } catch {
    return null;
  }
}

function sign(payload: string, secret: string): string {
  const key = createHash("sha256")
    .update("vana-data-app-starter/request-binding/v1\0")
    .update(secret)
    .digest();
  return createHmac("sha256", key).update(payload).digest("base64url");
}

function safeEqual(provided: string, expected: string): boolean {
  const providedBytes = Buffer.from(provided);
  const expectedBytes = Buffer.from(expected);
  return (
    providedBytes.length === expectedBytes.length &&
    timingSafeEqual(providedBytes, expectedBytes)
  );
}

function isRequestBinding(value: unknown): value is RequestBinding {
  if (!isRecord(value) || !isRecord(value.runtime)) return false;
  return (
    value.version === BINDING_VERSION &&
    typeof value.requestId === "string" &&
    value.requestId.length > 0 &&
    value.appId === VANA_APP.id &&
    value.source === VANA_APP.source &&
    value.scope === VANA_APP.scope &&
    typeof value.returnOrigin === "string" &&
    Number.isFinite(value.expiresAt) &&
    (value.runtime.env === "dev" || value.runtime.env === "production") &&
    (value.runtime.network === "moksha" || value.runtime.network === "mainnet")
  );
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

import type { RequestBinding } from "./binding";

type ConsumeOnceOptions = {
  maxEntries: number;
  now: () => number;
};

type RetainedRead = {
  expiresAt: number;
  read: Promise<unknown>;
  state: "pending" | "succeeded";
};

const MAX_RETAINED_READS = 100;

export function createConsumeOnce(options: ConsumeOnceOptions) {
  const reads = new Map<string, RetainedRead>();

  return function consumeOnce<T>(
    binding: RequestBinding,
    consume: () => Promise<T>,
  ): Promise<T> {
    const now = options.now();
    if (binding.expiresAt <= now) {
      return Promise.reject(new Error("The request binding has expired."));
    }

    for (const [retainedKey, retained] of reads) {
      if (retained.state === "succeeded" && retained.expiresAt <= now) {
        reads.delete(retainedKey);
      }
    }

    const key = bindingKey(binding);
    const existing = reads.get(key);
    if (existing) return existing.read as Promise<T>;
    if (reads.size >= options.maxEntries) {
      return Promise.reject(
        new Error("Approved read coordination is at capacity."),
      );
    }

    const read = Promise.resolve().then(consume);
    const retained: RetainedRead = {
      expiresAt: binding.expiresAt,
      read,
      state: "pending",
    };
    reads.set(key, retained);
    void read.then(
      () => {
        retained.state = "succeeded";
        if (retained.expiresAt <= options.now() && reads.get(key) === retained) {
          reads.delete(key);
        }
      },
      () => {
        if (reads.get(key) === retained) reads.delete(key);
      },
    );
    return read;
  };
}

export const consumeApprovedReadOnce = createConsumeOnce({
  maxEntries: MAX_RETAINED_READS,
  now: Date.now,
});

function bindingKey(binding: RequestBinding): string {
  return JSON.stringify([
    binding.version,
    binding.requestId,
    binding.appId,
    binding.source,
    binding.scope,
    binding.returnOrigin,
    binding.runtime.env,
    binding.runtime.network,
    binding.expiresAt,
  ]);
}

import {
  AccessNotApprovedError,
  type AccessRequestStatus,
} from "@opendatalabs/vana-sdk/server";
import { VANA_APP } from "./constants";

export function assertLinkedInReadReady(status: AccessRequestStatus): void {
  if (
    (status.status !== "approved" && status.status !== "ready_for_read") ||
    status.scope !== VANA_APP.scope
  ) {
    throw new AccessNotApprovedError("LinkedIn profile capability is not ready.");
  }
}

export const VANA_APP = {
  id: "linkedin-profile-snapshot",
  name: "LinkedIn Profile Snapshot",
  source: "linkedin",
  scope: "linkedin.profile",
} as const;

export const REQUEST_BINDING_TTL_MS = 10 * 60 * 1000;

import {
  AccessNotApprovedError,
  DirectConfigError,
  PaymentRequiredError,
  PersonalServerReadError,
} from "@opendatalabs/vana-sdk/server";
import { LaunchRuntimeError } from "./runtime";

export type ClientErrorKind =
  | "invalid_request"
  | "unavailable"
  | "not_ready"
  | "payment_required"
  | "failed";

export type ClientError = {
  kind: ClientErrorKind;
  error: string;
  status: number;
};

export function mapClientError(error: unknown): ClientError {
  if (error instanceof LaunchRuntimeError) {
    return { kind: "invalid_request", error: error.message, status: 400 };
  }
  if (error instanceof PaymentRequiredError) {
    return {
      kind: "payment_required",
      error: "The app's escrow balance cannot cover this read. Fund the app identity and retry.",
      status: 402,
    };
  }
  if (error instanceof AccessNotApprovedError) {
    return {
      kind: "not_ready",
      error: "The approved LinkedIn profile is not ready to read.",
      status: 409,
    };
  }
  if (error instanceof PersonalServerReadError || hasNetworkError(error)) {
    return {
      kind: "unavailable",
      error: "The Personal Server is temporarily unavailable.",
      status: 503,
    };
  }
  if (error instanceof DirectConfigError) {
    return {
      kind: "failed",
      error: "The Vana app is not configured correctly.",
      status: 500,
    };
  }
  return { kind: "failed", error: "The Vana request failed.", status: 500 };
}

function hasNetworkError(error: unknown, depth = 0): boolean {
  if (!isRecord(error) || depth > 5) return false;
  if (typeof error.code === "string" && /^E[A-Z_]+$/.test(error.code)) return true;
  return hasNetworkError(error.cause, depth + 1);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

import type { NextRequest } from "next/server";
import { readRequestBinding } from "./binding";
import { getVanaController, getVanaServerConfig } from "./server";

export function requestIdFromUrl(url: string): string | null {
  const values = new URL(url).searchParams.getAll("requestId");
  if (values.length !== 1) return null;
  const requestId = values[0]?.trim();
  return requestId && requestId.length <= 256 ? requestId : null;
}

export function getBoundVanaRequest(request: NextRequest, requestId: string) {
  const config = getVanaServerConfig();
  const binding = readRequestBinding(
    request.cookies,
    { requestId, returnOrigin: config.returnOrigin },
    config.appPrivateKey,
  );
  if (!binding) return null;
  return { binding, controller: getVanaController(binding.runtime, config), config };
}

export function noStore<T extends Response>(response: T): T {
  response.headers.set("Cache-Control", "no-store");
  return response;
}

export function jsonNoStore(data: unknown, init?: ResponseInit): Response {
  return noStore(Response.json(data, init));
}

import type { AccessRequestStatusValue } from "@opendatalabs/vana-sdk/server";

export type ReturnState = {
  title: string;
  message: string;
  kind: "success" | "waiting" | "error";
};

export function returnStateForStatus(status: AccessRequestStatusValue): ReturnState {
  switch (status) {
    case "completed":
      return {
        title: "Profile read complete",
        message: "The authoritative request status is complete. You can return to the profile tab.",
        kind: "success",
      };
    case "approved":
    case "ready_for_read":
      return {
        title: "Profile approved",
        message: "The request is ready. Keep this tab open while the original tab finishes the approved read.",
        kind: "waiting",
      };
    case "pending":
      return {
        title: "Approval still pending",
        message: "The request has not reached a read-ready state yet.",
        kind: "waiting",
      };
    case "denied":
      return {
        title: "Request not completed",
        message: "No approved profile was made available. Return to the profile tab and retry after the platform is ready.",
        kind: "error",
      };
    case "expired":
      return {
        title: "Request expired",
        message: "The authoritative request status is expired. Return to the profile tab to start a new request.",
        kind: "error",
      };
  }
}

export type VanaRuntime = {
  env: "dev" | "production";
  network: "moksha" | "mainnet";
};

export class LaunchRuntimeError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "LaunchRuntimeError";
  }
}

export function resolveLaunchRuntime(params: URLSearchParams): VanaRuntime {
  const vanaEnvs = params.getAll("vana_env");
  const networks = params.getAll("network");

  if (vanaEnvs.length > 1 || networks.length > 1) {
    throw new LaunchRuntimeError("Launch runtime parameters may only be provided once.");
  }

  const vanaEnv = vanaEnvs[0] ?? null;
  const network = networks[0] ?? null;

  if (vanaEnv !== null && vanaEnv !== "dev") {
    throw new LaunchRuntimeError("Invalid vana_env. Expected dev or no value.");
  }

  if (network !== null && network !== "moksha" && network !== "mainnet") {
    throw new LaunchRuntimeError("Invalid network. Expected moksha, mainnet, or no value.");
  }

  if (vanaEnv === "dev" && network === "mainnet") {
    throw new LaunchRuntimeError("The dev environment only supports the moksha network.");
  }

  return {
    env: vanaEnv === "dev" ? "dev" : "production",
    network: vanaEnv === "dev" ? "moksha" : (network ?? "mainnet"),
  };
}

import "server-only";

import { createDirectDataController } from "@opendatalabs/vana-sdk/server";
import { resolveAppUrl } from "./app-url";
import { VANA_APP } from "./constants";
import type { VanaRuntime } from "./runtime";

type Controller = ReturnType<typeof createDirectDataController>;

const controllers = new Map<string, Controller>();

export type VanaServerConfig = {
  appPrivateKey: string;
  appUrl: string;
  returnOrigin: string;
  returnUrl: string;
};

export function getVanaServerConfig(): VanaServerConfig {
  const appPrivateKey = process.env.VANA_APP_PRIVATE_KEY?.trim();
  const rawAppUrl = process.env.VANA_APP_URL?.trim();

  if (!appPrivateKey) throw new Error("Missing VANA_APP_PRIVATE_KEY.");
  if (!rawAppUrl) throw new Error("Missing VANA_APP_URL.");

  const resolvedUrl = resolveAppUrl(rawAppUrl);
  return {
    appPrivateKey,
    ...resolvedUrl,
  };
}

export function getVanaController(runtime: VanaRuntime, config = getVanaServerConfig()): Controller {
  const key = `${runtime.env}:${runtime.network}`;
  const cached = controllers.get(key);
  if (cached) return cached;

  // SDK 3.13.4 keeps production app/API endpoints for production+moksha while
  // deriving Moksha's escrow chain defaults from `network`. Do not hardcode a
  // gateway here: that would turn an SDK-owned endpoint decision into app drift.
  const controller = createDirectDataController({
    env: runtime.env,
    network: runtime.network,
    appPrivateKey: config.appPrivateKey,
    app: {
      id: VANA_APP.id,
      name: VANA_APP.name,
      homepageUrl: config.appUrl,
    },
    source: VANA_APP.source,
    scopes: [VANA_APP.scope],
  });
  controllers.set(key, controller);
  return controller;
}

export type LinkedInWorkItem = {
  title: string;
  company: string;
  period: string;
};

export type LinkedInEducationItem = {
  school: string;
  degree: string;
  period: string;
};

export type LinkedInSnapshot = {
  name: string;
  headline: string;
  work: LinkedInWorkItem[];
  education: LinkedInEducationItem[];
  skills: string[];
};

type RecordValue = Record<string, unknown>;

export function mapLinkedInProfile(input: unknown): LinkedInSnapshot {
  const profile = unwrapProfile(input);
  if (!profile) return emptyLinkedInSnapshot();

  const name =
    firstString(profile, ["fullName", "full_name", "name"]) ||
    [firstString(profile, ["firstName", "first_name"]), firstString(profile, ["lastName", "last_name"])]
      .filter(Boolean)
      .join(" ");

  return {
    name: name || "LinkedIn profile",
    headline: firstString(profile, ["headline", "occupation"]),
    work: firstArray(profile, [
      "experience",
      "experiences",
      "positions",
      "workExperience",
      "work_experience",
    ])
      .map(mapWorkItem)
      .filter((item): item is LinkedInWorkItem => item !== null),
    education: firstArray(profile, ["education", "educations", "schools"])
      .map(mapEducationItem)
      .filter((item): item is LinkedInEducationItem => item !== null),
    skills: firstArray(profile, ["skills", "topSkills", "top_skills"])
      .map(skillName)
      .filter((skill): skill is string => skill !== ""),
  };
}

export function emptyLinkedInSnapshot(): LinkedInSnapshot {
  return {
    name: "LinkedIn profile",
    headline: "",
    work: [],
    education: [],
    skills: [],
  };
}

function unwrapProfile(input: unknown, depth = 0): RecordValue | null {
  if (depth > 4) return null;
  if (Array.isArray(input)) return unwrapProfile(input[0], depth + 1);
  if (!isRecord(input)) return null;

  if (hasProfileFields(input)) return input;
  if ("linkedin.profile" in input) return unwrapProfile(input["linkedin.profile"], depth + 1);
  if ("data" in input) return unwrapProfile(input.data, depth + 1);
  if ("result" in input) return unwrapProfile(input.result, depth + 1);
  return null;
}

function hasProfileFields(value: RecordValue): boolean {
  return [
    "fullName",
    "full_name",
    "name",
    "firstName",
    "first_name",
    "headline",
    "occupation",
    "experience",
    "work_experience",
    "education",
    "skills",
  ].some((key) => key in value);
}

function mapWorkItem(input: unknown): LinkedInWorkItem | null {
  if (!isRecord(input)) return null;
  const title = firstString(input, ["title", "jobTitle", "job_title", "position", "role"]);
  const company = namedString(
    firstValue(input, ["companyName", "company_name", "company", "organization", "employer"]),
  );
  if (!title && !company) return null;

  return {
    title,
    company,
    period: periodString(input),
  };
}

function mapEducationItem(input: unknown): LinkedInEducationItem | null {
  if (!isRecord(input)) return null;
  const school = namedString(
    firstValue(input, ["schoolName", "school_name", "school", "institution", "university"]),
  );
  const degree = firstString(input, ["degree", "degreeName", "degree_name"]);
  if (!school && !degree) return null;

  return {
    school,
    degree,
    period: firstString(input, ["years", "dates", "dateRange", "date_range"]) || periodString(input),
  };
}

function periodString(input: RecordValue): string {
  const combined = firstString(input, ["dates", "period", "dateRange", "date_range"]);
  if (combined) return combined;

  const start = dateString(firstValue(input, ["startDate", "start_date", "startsAt", "starts_at", "start"]));
  const end = dateString(firstValue(input, ["endDate", "end_date", "endsAt", "ends_at", "end"]));
  const current = firstValue(input, ["isCurrent", "is_current", "current"]) === true;
  if (start && (end || current)) return `${start} - ${end || "Present"}`;
  return start || end;
}

function skillName(input: unknown): string {
  if (typeof input === "string") return clean(input);
  return isRecord(input) ? firstString(input, ["name", "skill", "title"]) : "";
}

function namedString(input: unknown): string {
  if (typeof input === "string") return clean(input);
  return isRecord(input) ? firstString(input, ["name", "title", "label"]) : "";
}

function dateString(input: unknown): string {
  if (typeof input === "string") return clean(input);
  if (typeof input === "number" && Number.isFinite(input)) return String(input);
  if (!isRecord(input)) return "";
  const year = input.year;
  const month = input.month;
  if (typeof year !== "number" || !Number.isFinite(year)) return "";
  if (typeof month === "number" && month >= 1 && month <= 12) {
    return `${year}-${String(month).padStart(2, "0")}`;
  }
  return String(year);
}

function firstArray(input: RecordValue, keys: string[]): unknown[] {
  for (const key of keys) {
    if (Array.isArray(input[key])) return input[key];
  }
  return [];
}

function firstString(input: RecordValue, keys: string[]): string {
  const value = firstValue(input, keys);
  return typeof value === "string" ? clean(value) : "";
}

function firstValue(input: RecordValue, keys: string[]): unknown {
  for (const key of keys) {
    if (input[key] !== undefined && input[key] !== null) return input[key];
  }
  return undefined;
}

function clean(value: string): string {
  return value.trim();
}

function isRecord(value: unknown): value is RecordValue {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

