import { createRequestBinding, setRequestBindingCookie } from "@/lib/vana/binding";
import { mapClientError } from "@/lib/vana/errors";
import { jsonNoStore, noStore } from "@/lib/vana/response";
import { resolveLaunchRuntime } from "@/lib/vana/runtime";
import { getVanaController, getVanaServerConfig } from "@/lib/vana/server";
import { NextRequest, NextResponse } from "next/server";

export async function POST(request: NextRequest) {
  try {
    const runtime = resolveLaunchRuntime(new URL(request.url).searchParams);
    const config = getVanaServerConfig();
    const controller = getVanaController(runtime, config);
    const accessRequest = await controller.createAccessRequest({ returnUrl: config.returnUrl });
    const binding = createRequestBinding(
      {
        requestId: accessRequest.requestId,
        runtime,
        returnOrigin: config.returnOrigin,
      },
      config.appPrivateKey,
    );
    const response = noStore(NextResponse.json(accessRequest));
    setRequestBindingCookie(
      response.cookies,
      accessRequest.requestId,
      binding,
      process.env.NODE_ENV === "production",
    );
    return response;
  } catch (error) {
    const clientError = mapClientError(error);
    console.error("[vana/request] Request creation failed", error);
    return jsonNoStore(
      { kind: clientError.kind, error: clientError.error },
      { status: clientError.status },
    );
  }
}

import { mapClientError } from "@/lib/vana/errors";
import { assertLinkedInReadReady } from "@/lib/vana/capability";
import { getBoundVanaRequest, requestIdFromUrl } from "@/lib/vana/request";
import { jsonNoStore } from "@/lib/vana/response";
import { NextRequest } from "next/server";

export async function GET(request: NextRequest) {
  const requestId = requestIdFromUrl(request.url);
  if (!requestId) {
    return jsonNoStore(
      { kind: "invalid_request", error: "A single requestId is required." },
      { status: 400 },
    );
  }

  try {
    const bound = getBoundVanaRequest(request, requestId);
    if (!bound) {
      return jsonNoStore(
        { kind: "unavailable", error: "This request is not available in this browser session." },
        { status: 403 },
      );
    }

    const status = await bound.controller.getAccessRequestStatus(requestId);
    if (status.status === "approved" || status.status === "ready_for_read") {
      assertLinkedInReadReady(status);
    }
    return jsonNoStore({ status: status.status });
  } catch (error) {
    const clientError = mapClientError(error);
    console.error(`[vana/status] Status failed for ${requestId}`, error);
    return jsonNoStore(
      { kind: clientError.kind, error: clientError.error },
      { status: clientError.status },
    );
  }
}

import { mapLinkedInProfile } from "@/lib/linkedin-profile";
import { assertLinkedInReadReady } from "@/lib/vana/capability";
import { consumeApprovedReadOnce } from "@/lib/vana/consume-once";
import { mapClientError } from "@/lib/vana/errors";
import { getBoundVanaRequest, requestIdFromUrl } from "@/lib/vana/request";
import { jsonNoStore } from "@/lib/vana/response";
import { NextRequest } from "next/server";

export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  const requestId = requestIdFromUrl(request.url);
  if (!requestId) {
    return jsonNoStore(
      { kind: "invalid_request", error: "A single requestId is required." },
      { status: 400 },
    );
  }

  try {
    const bound = getBoundVanaRequest(request, requestId);
    if (!bound) {
      return jsonNoStore(
        { kind: "unavailable", error: "This request is not available in this browser session." },
        { status: 403 },
      );
    }

    const result = await consumeApprovedReadOnce(bound.binding, async () => {
      const status = await bound.controller.getAccessRequestStatus(requestId);
      assertLinkedInReadReady(status);
      return bound.controller.readApprovedData({ requestId });
    });
    return jsonNoStore({
      scope: result.scope,
      data: mapLinkedInProfile(result.data),
    });
  } catch (error) {
    const clientError = mapClientError(error);
    console.error(`[vana/read] Read failed for ${requestId}`, error);
    return jsonNoStore(
      { kind: clientError.kind, error: clientError.error },
      { status: clientError.status },
    );
  }
}

import { readRequestBinding } from "@/lib/vana/binding";
import { assertLinkedInReadReady } from "@/lib/vana/capability";
import { returnStateForStatus, type ReturnState } from "@/lib/vana/return-state";
import { getVanaController, getVanaServerConfig } from "@/lib/vana/server";
import { cookies } from "next/headers";

export default async function ConnectReturn({
  searchParams,
}: {
  searchParams: Promise<Record<string, string | string[] | undefined>>;
}) {
  const params = await searchParams;
  const requestId = typeof params.request_id === "string" ? params.request_id : null;
  const state = await authoritativeReturnState(requestId);

  return (
    <main className="return-shell">
      <p className={`mode-label ${state.kind}`}>Verified request status</p>
      <h1>{state.title}</h1>
      <p>{state.message}</p>
      <a className="primary-action return-action" href="/">Return to profile snapshot</a>
    </main>
  );
}

async function authoritativeReturnState(requestId: string | null): Promise<ReturnState> {
  if (!requestId || requestId.length > 256) return invalidReturn();

  try {
    const config = getVanaServerConfig();
    const binding = readRequestBinding(
      await cookies(),
      { requestId, returnOrigin: config.returnOrigin },
      config.appPrivateKey,
    );
    if (!binding) return invalidReturn();

    const status = await getVanaController(binding.runtime, config).getAccessRequestStatus(requestId);
    if (status.status === "approved" || status.status === "ready_for_read") assertLinkedInReadReady(status);
    return returnStateForStatus(status.status);
  } catch (error) {
    console.error(`[vana/return] Return verification failed for ${requestId}`, error);
    return {
      title: "Status unavailable",
      message: "The request status could not be verified. Return to the profile tab to try again.",
      kind: "error",
    };
  }
}

function invalidReturn(): ReturnState {
  return {
    title: "Request unavailable",
    message: "This return does not match a request from the current browser session.",
    kind: "error",
  };
}

